history.content:
There is a miscompilation issue report in LoopVectorize: 

The code generates incorrect code in Clang 15.0.0 to the latest trunk on compiler explorer (57b78faa9eb08017d95bb4e43242648953b08c13)

```cpp
struct struct_with_sentinal
{
	struct_with_sentinal()
	{
         m_sentinel = &m_sentinel;
	}
	
	void * m_sentinel;
};

template <typename T, int T_SIZE>
struct fixed_array
{
	T m_data[T_SIZE];
};

fixed_array<struct_with_sentinal, 10240> my_test_array;
```


Current output (with `-std=c++20 -O3 -mavx2`)
```asm
_GLOBAL__sub_I_example.cpp:             # @_GLOBAL__sub_I_example.cpp
        xor     eax, eax
        lea     rcx, [rip + my_test_array]
.LBB1_1:                                # =>This Inner Loop Header: Depth=1
        lea     rdx, [rcx + rax]
        vmovq   xmm0, rdx
        vpbroadcastq    ymm0, xmm0
        lea     rdx, [rax + rcx]
        add     rdx, 32
        vmovq   xmm1, rdx
        vpbroadcastq    ymm1, xmm1
        lea     rdx, [rax + rcx + 64]
        vmovq   xmm2, rdx
        vpbroadcastq    ymm2, xmm2
        lea     rdx, [rax + rcx + 96]
        vmovq   xmm3, rdx
        vpbroadcastq    ymm3, xmm3
        vmovdqu ymmword ptr [rax + rcx], ymm0
        vmovdqu ymmword ptr [rax + rcx + 32], ymm1
        vmovdqu ymmword ptr [rax + rcx + 64], ymm2
        vmovdqu ymmword ptr [rax + rcx + 96], ymm3
        sub     rax, -128
        cmp     rax, 81920
        jne     .LBB1_1
        vzeroupper
        ret
```

The `vpbroadcastq` and then `movdqu` back into the array ends up generating an array with every 4 elements pointing to the first element not to themselves.

The last known good code gen appears to be in Clang 14.0.0 (Based on looking back in compiler explorer)

Compiler explorer link for example code gen:
https://godbolt.org/z/eqx5avca9

The maintainers proposed the following patch to fix the issue:

commit 962c306a11d0a21c884c12e18825b8a41ba1bd7d
Author: Florian Hahn <flo@fhahn.com>
Date:   Fri Mar 17 16:26:07 2023 +0000

    [LV] Don't consider pointer as uniform if it is also stored.

    Update isVectorizedMemAccessUse to also check if the pointer is stored.
    This prevents LV to incorrectly consider a pointer as uniform if it is
    used as both pointer and stored by the same StoreInst.

    Fixes #61396.

diff --git a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
index cff8c8031ec4..e89eacdaa964 100644
--- a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
+++ b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
@@ -4734,11 +4734,17 @@ void LoopVectorizationCostModel::collectLoopUniforms(ElementCount VF) {
             WideningDecision == CM_Interleave);
   };

-
   // Returns true if Ptr is the pointer operand of a memory access instruction
-  // I, and I is known to not require scalarization.
+  // I, I is known to not require scalarization, and the pointer is not also
+  // stored.
   auto isVectorizedMemAccessUse = [&](Instruction *I, Value *Ptr) -> bool {
-    return getLoadStorePointerOperand(I) == Ptr && isUniformDecision(I, VF);
+    auto GetStoredValue = [I]() -> Value * {
+      if (!isa<StoreInst>(I))
+        return nullptr;
+      return I->getOperand(0);
+    };
+    return getLoadStorePointerOperand(I) == Ptr && isUniformDecision(I, VF) &&
+           GetStoredValue() != Ptr;
   };

   // Holds a list of values which are known to have at least one uniform use.
@@ -4784,8 +4790,8 @@ void LoopVectorizationCostModel::collectLoopUniforms(ElementCount VF) {
       if (isUniformMemOpUse(&I))
         addToWorklistIfAllowed(&I);

-      if (isUniformDecision(&I, VF)) {
-        assert(isVectorizedMemAccessUse(&I, Ptr) && "consistency check");
+      if (isVectorizedMemAccessUse(&I, Ptr)) {
+        assert(isUniformDecision(&I, VF) && "consistency check");
         HasUniformUse.insert(Ptr);
       }
     }


